// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedDay, setSelectedDay] = useState<string>('');

  const normalizedCondition = useMemo(() => {
    return String(props.condition || '').toLowerCase();
  }, [props.condition]);

  const displayedForecast = useMemo(() => {
    return Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : [];
  }, [props.forecast]);

  const forecastSlots = useMemo(() => {
    return Array.from({ length: 5 }, (_, index) => displayedForecast[index] || {});
  }, [displayedForecast]);

  const extraForecastCount = useMemo(() => {
    return Array.isArray(props.forecast) && props.forecast.length > 5 ? props.forecast.length - 5 : 0;
  }, [props.forecast]);

  useEffect(() => {
    if (!selectedDay) {
      const firstNamedDay = forecastSlots.find((item) => String(item.day || '').trim().length > 0);
      if (firstNamedDay) setSelectedDay(String(firstNamedDay.day || ''));
    }
  }, [forecastSlots, selectedDay]);

  const selectedForecast = useMemo(() => {
    return forecastSlots.find((item) => String(item.day || '') === selectedDay) || null;
  }, [forecastSlots, selectedDay]);

  const conditionEmoji = useMemo(() => {
    if (normalizedCondition.includes('sun') || normalizedCondition.includes('clear')) return '☀️';
    if (normalizedCondition.includes('cloud')) return '☁️';
    if (normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle')) return '🌧️';
    if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
    if (normalizedCondition.includes('snow') || normalizedCondition.includes('sleet')) return '❄️';
    if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist') || normalizedCondition.includes('haze')) return '🌫️';
    return '';
  }, [normalizedCondition]);

  const conditionTone = useMemo(() => {
    if (normalizedCondition.includes('rain') || normalizedCondition.includes('storm')) return 'warning';
    if (normalizedCondition.includes('clear') || normalizedCondition.includes('sun')) return 'success';
    if (normalizedCondition.includes('snow')) return 'default';
    return 'primary';
  }, [normalizedCondition]);

  const isLoading = (props.city || '').trim().length === 0 && forecastSlots.every((item) => item.high == null && item.low == null);
  const errorMessage = String((props as Props & { error?: string }).error || '');
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-5)">
            <Row justify="between" align="start" wrap gap="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                  Current Weather
                </Text>
                <Heading level={2} color="var(--ggui-color-onSurface)">
                  {props.city}
                </Heading>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Text size="4xl" weight="bold" color="var(--ggui-color-primary-700)">
                    {props.temperature}°{props.unit}
                  </Text>
                  {props.condition ? (
                    <Text size="3xl" is="span" role="img" aria-label={props.condition}>
                      {conditionEmoji}
                    </Text>
                  ) : null}
                </Row>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Badge variant={conditionTone === 'warning' ? 'warning' : conditionTone === 'success' ? 'success' : conditionTone === 'default' ? 'default' : 'primary'}>
                    {props.condition}
                  </Badge>
                </Row>
              </Stack>

              <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-3">
                  <Row align="center" gap="var(--ggui-spacing-2)">
                    <Icon name="droplets" size={16} color="var(--ggui-color-primary-600)" />
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                    <Spacer size="flex" />
                    <Text weight="semibold" color="var(--ggui-color-onSurface)">
                      {props.humidity}%
                    </Text>
                  </Row>
                  <Divider margin="var(--ggui-spacing-1)" color="var(--ggui-color-outlineVariant)" />
                  <Row align="center" gap="var(--ggui-spacing-2)">
                    <Icon name="wind" size={16} color="var(--ggui-color-primary-600)" />
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
                    <Spacer size="flex" />
                    <Text weight="semibold" color="var(--ggui-color-onSurface)">
                      {props.windSpeed} km/h
                    </Text>
                  </Row>
                </Stack>
              </Card>
            </Row>


            {selectedForecast && (
              <Alert variant="info" title={selectedForecast.day ? `Selected: ${selectedForecast.day}` : undefined}>
                High {selectedForecast.high ?? '—'}°{props.unit} • Low {selectedForecast.low ?? '—'}°{props.unit}
              </Alert>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">
              5-Day Forecast
            </Heading>
            {isLoading ? (
              <Row justify="center" align="center">
                <Spinner size={24} color="var(--ggui-color-primary-600)" />
              </Row>
            ) : errorMessage ? (
              <Alert variant="error" title="Unable to load weather">
                {errorMessage} Please try again.
              </Alert>
            ) : displayedForecast.length === 0 ? (
              <Alert variant="warning" title="No forecast available">
                Forecast data is currently unavailable.
              </Alert>
            ) : (
              <Row gap="var(--ggui-spacing-3)" wrap>
                {forecastSlots.map((item, index) => {
                  const dayValue = String(item.day || '');
                  const isSelected = dayValue === selectedDay;
                  return (
                    <Box key={`${dayValue}-${index}`} padding="var(--ggui-spacing-0)">
                      <Button
                        variant={isSelected ? 'secondary' : 'ghost'}
                        size="sm"
                        aria-pressed={isSelected}
                        onClick={() => setSelectedDay(dayValue)}
                      >
                        <Stack align="center" gap="var(--ggui-spacing-1)">
                          <Text variant="label" color={isSelected ? 'var(--ggui-color-primary-700)' : 'var(--ggui-color-onSurface)'}>
                            {dayValue}
                          </Text>
                          {item.icon ? <Text size="2xl" is="span" aria-hidden>
                            {item.icon}
                          </Text> : null}
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            {item.high ?? '—'}° / {item.low ?? '—'}°
                          </Text>
                        </Stack>
                      </Button>
                    </Box>
                  );
                })}
              </Row>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

