// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);
  const totalSteps = 5;
  const [submitError, setSubmitError] = useState('');
  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email), [email]);
  const nameError = touchedName && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = touchedEmail && (email.trim().length === 0 || !emailValid) ? 'Please enter a valid email address.' : '';
  const canNext = useMemo(() => {
    if (step === 1) return name.trim().length > 0 && emailValid;
    if (step === 2) return satisfaction !== '';
    if (step === 3) return features.length > 0;
    if (step === 4) return true;
    return true;
  }, [step, name, emailValid, satisfaction, features.length]);
  const satisfactionOptions = useMemo(
    () => (props.satisfactionLabels ?? []).map((label, index) => ({ value: String(index + 1), label })),
    [props.satisfactionLabels]
  );
  const progressValue = (step / totalSteps) * 100;
  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);
  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
    }
    if (!canNext) return;
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  }, [step, canNext]);
  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);
  const handleSubmit = useCallback(async () => {
    setSubmitError('');
    try {
      const selectedSatisfaction = satisfactionOptions.find((option) => option.value === satisfaction);
      if (!selectedSatisfaction) {
        setSubmitError('Please select a valid satisfaction rating.');
        return;
      }
      const payload: ActionSubmitPayload = {
        name: name.trim(),
        email: email.trim(),
        satisfaction: Number(selectedSatisfaction.value),
        features,
        comments,
      };
      await (props as Props & { onSubmit?: (payload: ActionSubmitPayload) => void | Promise<void> }).onSubmit?.(payload);
    } catch (_error) {
      setSubmitError('Submission failed. Please try again.');
    }
  }, [name, email, satisfaction, satisfactionOptions, features, comments, props]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Survey</Heading>
        <Card padding="var(--ggui-spacing-4)" border shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurface)" is="span">
                <span aria-live="polite">Step {step} of {totalSteps}</span>
              </Text>
              <Badge variant="primary">Survey</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" aria-label={`Survey progress: step ${step} of ${totalSteps}`} />
          </Stack>
        </Card>


        <Card padding="var(--ggui-spacing-6)" border shadow="sm" radius="lg">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Contact Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  if (touchedName) setTouchedName(true);
                }}
                onBlur={() => setTouchedName(true)}
                required
                error={nameError || undefined}
                aria-invalid={!!nameError}
                placeholder="Enter your full name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  if (touchedEmail) setTouchedEmail(true);
                }}
                onBlur={() => setTouchedEmail(true)}
                required
                error={emailError || undefined}
                aria-invalid={!!emailError}
                placeholder="you@example.com"
              />

            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Choose one option from 1 to 5.</Text>
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Feature Interests</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Select all features you are interested in.</Text>
              {(props.featureOptions?.length ?? 0) === 0 ? (
                <Alert variant="info">No feature options available.</Alert>
              ) : (
                <Stack gap="var(--ggui-spacing-2)">
                  {(props.featureOptions ?? []).map((feature) => (
                    <Box
                      key={feature}
                      as={Clickable}
                      onClick={() => toggleFeature(feature, !features.includes(feature))}
                      hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                      padding="var(--ggui-spacing-3)"
                      background="var(--ggui-color-surfaceVariant)"
                      borderRadius="var(--ggui-shape-radius-md)"
                    >
                      <Checkbox
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    </Box>
                  ))}
                </Stack>
              )}
            </Stack>

          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={setComments}
                maxLength={500}
                showCount
                rows={6}
                helperText="Share any additional feedback."
                placeholder="Tell us more about your experience..."
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Divider margin="var(--ggui-spacing-4)" />
              <Stack gap="var(--ggui-spacing-2)">
                <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfactionOptions.find((option) => option.value === satisfaction)?.label || '-'}</Text>
                <Text>
                  <Text is="span" weight="semibold">Features:</Text>{' '}
                  {features.length > 0 ? features.join(', ') : 'None selected'}
                </Text>
                <Text><Text is="span" weight="semibold">Comments:</Text> {comments || 'No comments provided'}</Text>
              </Stack>
            </Stack>
          )}
        </Card>
        {submitError && <Alert variant="error">{submitError}</Alert>}
        <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
          <Button variant="outline" disabled={step === 1} as={Clickable} onClick={handleBack}>
            Back
          </Button>
          {step < totalSteps ? (
            <Button variant="primary" disabled={!canNext} as={Clickable} onClick={handleNext}>
              Next
            </Button>
          ) : (
            <Button variant="primary" as={Clickable} onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

