      return safeElements;
    }
    return safeElements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [safeElements, searchQuery]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    safeElements.forEach((el) => {
      set.add(normalizeCategory(el.category));
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) {
      return null;
    }
    return filteredElements.find((el) => el.atomicNumber === selectedAtomicNumber) || null;
  }, [filteredElements, selectedAtomicNumber]);

