export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [draft, setDraft] = useState<string>('');
  const [activeTypingSender, setActiveTypingSender] = useState<string>('');
  const [sendError, setSendError] = useState<string>('');
  const [isSending, setIsSending] = useState<boolean>(false);
  const messagesEndRef = useRef<HTMLDivElement | null>(null);
  useEffect(() => {
    setAllMessages(props.messages || []);
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) return;
    setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) return;
    if (typing.latest.active && typing.latest.sender && typing.latest.sender !== props.currentUser) {
      setActiveTypingSender(typing.latest.sender);
    } else if (!typing.latest.active) {
      setActiveTypingSender('');
    }
  }, [typing.latest, props.currentUser]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [allMessages.length, activeTypingSender]);

  const handleSend = useCallback(async () => {
    const trimmed = draft.trim();
    if (!trimmed || isSending) return;
    const timestamp = new Date().toISOString();
    setIsSending(true);
    try {
      sendMessage({ text: trimmed, timestamp });
      setAllMessages((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp }]);
      setDraft('');
      setSendError('');
    } catch (_error) {
      setSendError('Message failed to send. Please try again.');
    } finally {
      setIsSending(false);
    }
  }, [draft, isSending, props.currentUser, sendMessage]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (allMessages || []).forEach((item) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === item.sender) {
        last.items.push(item);
      } else {
        groups.push({ sender: item.sender, items: [item] });
      }
    });
    return groups;
  }, [allMessages]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
