              ) : null}
            </Row>
          </Row>


          <Divider margin="var(--ggui-spacing-2)" />

          <Box
            padding="var(--ggui-spacing-2)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack gap="var(--ggui-spacing-3)">
              {sendError ? <Alert variant="error">{sendError}</Alert> : null}
              {(props.messages || []).length === 0 && (message.all || []).length === 0 ? (
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Spinner size={16} />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Connecting to chat…
                  </Text>
                </Row>
              ) : null}
              {(groupedMessages || []).length === 0 ? (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  No messages yet. Start the conversation.
                </Text>
              ) : (
                <Box maxHeight="60vh" overflowY="auto" role="log" aria-live="polite" aria-relevant="additions text" aria-label="Chat messages">
                  <Stack gap="var(--ggui-spacing-3)">
                    {(groupedMessages || []).map((group, groupIndex) => {
                      const isOwn = (group.sender || '') === props.currentUser;
                      return (
                        <Stack key={`group-${groupIndex}`} gap="var(--ggui-spacing-1}" align={isOwn ? 'end' : 'start'}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {group.sender || 'Unknown'}
                          </Text>
                          <Stack gap="var(--ggui-spacing-1)" align={isOwn ? 'end' : 'start'}>
                            {(group.items || []).map((msg, msgIndex) => (
                              <Box
                                key={`msg-${groupIndex}-${msgIndex}`}
                                padding="var(--ggui-spacing-2)"
                                background={
                                  isOwn
                                    ? 'var(--ggui-color-primary-600)'
                                    : 'var(--ggui-color-surfaceVariant)'
                                }
                                borderRadius="var(--ggui-shape-radius-md)"
                                style={{ maxWidth: '80%' }}
                              >
                                <Stack gap="var(--ggui-spacing-1)">
                                  <Text
                                    variant="bodySmall"
                                    color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}
                                  >
                                    {msg.text || ''}
                                  </Text>
                                  <Text
                                    variant="caption"
                                    color={isOwn ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                  >
                                    {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                                  </Text>
                                </Stack>
                              </Box>
                            ))}
                          </Stack>
                        </Stack>
                      );
                    })}
                    <Box ref={messagesEndRef} aria-hidden="true" />
                  </Stack>
                </Box>
              )}

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box padding="0" margin="0" style={{ flex: 1 }}>
                  <Input
                    label="Message"
                    placeholder="Type your message..."
                    value={draft}
                    disabled={isSending}
                    onChange={setDraft}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter') {
                        event.preventDefault();
                        handleSend();
                      }
                    }}
                  />
                </Box>
                <Button
                  variant="primary"
                  disabled={!draft.trim() || isSending}
                  onClick={handleSend}
                >
                  {isSending ? 'Sending…' : 'Send'}
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>

  );
}

