import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, boolean>>({});
  const [isLoading, setIsLoading] = useState<boolean>((props.stocks ?? []).length === 0);
  const [streamError, setStreamError] = useState<string | null>(null);
  const [lastPriceAnnouncement, setLastPriceAnnouncement] = useState<string>('');

  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    if ((props.stocks ?? []).length > 0) {
      setIsLoading(false);
    }
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }
    const incoming = priceUpdate.latest;
    setStocksState((prev) => {
      const existingIndex = prev.findIndex((s) => s.symbol === incoming.symbol);
      if (existingIndex === -1) {
        return prev;
      }
      const next = [...prev];
      const current = next[existingIndex];
      const nextPrice = incoming.price ?? current.price;
      const priceChanged = nextPrice !== current.price;
      next[existingIndex] = {
        ...current,
        price: nextPrice,
        change: incoming.change ?? current.change,
        changePercent: incoming.changePercent ?? current.changePercent,
      };
      if (priceChanged && incoming.symbol) {
        setFlashMap((currentFlash) => ({ ...currentFlash, [incoming.symbol as string]: true }));
        const symbol = incoming.symbol as string;
        setTimeout(() => {
          setFlashMap((currentFlash) => ({ ...currentFlash, [symbol]: false }));
        }, 900);
      if (incoming.symbol) {
        setLastPriceAnnouncement(
          `${incoming.symbol} ${formatPrice(incoming.price)} ${incoming.changePercent ?? 0 >= 0 ? 'up' : 'down'} ${formatPercent(Math.abs(incoming.changePercent ?? 0))}`
        );
      }
      return next;
    });
    setStreamError(null);
    setLastUpdated(new Date());
  }, [priceUpdate.latest, formatPrice, formatPercent]);

  useEffect(() => {
    if (marketStatus.latest) {
      if (marketStatus.latest.timestamp) {
        const parsed = new Date(marketStatus.latest.timestamp);
        if (!Number.isNaN(parsed.getTime())) {
          setLastUpdated(parsed);
          setStreamError(null);
          return;
        }
        setStreamError('Received malformed market status timestamp.');
      }
      setLastUpdated(new Date());
      setStreamError(null);
    }
  }, [marketStatus.latest]);

  useEffect(() => {
    if (!priceUpdate.latest && !marketStatus.latest) {
      const timeout = setTimeout(() => {
        setStreamError('Live stream is delayed or disconnected.');
      }, 15000);
      return () => clearTimeout(timeout);
    }
    return undefined;
  }, [priceUpdate.latest, marketStatus.latest]);

  const formatPrice = useCallback((value?: number) => `$${(value ?? 0).toFixed(2)}`, []);
  const formatDelta = useCallback((value?: number) => {
    const safe = value ?? 0;
    const sign = safe > 0 ? '+' : '';
    return `${sign}${safe.toFixed(2)}`;
  }, []);
  const formatPercent = useCallback((value?: number) => {
    const safe = value ?? 0;
    const sign = safe > 0 ? '+' : '';
    return `${sign}${safe.toFixed(2)}%`;
  }, []);

  const isFlashing = useCallback(
    (symbol?: string) => {
      if (!symbol) {
        return false;
      }
      return !!flashMap[symbol];
    },
    [flashMap],
  );

  const renderedStocks = useMemo(() => stocksState ?? [], [stocksState]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Row justify="between" align="center" wrap>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface)" is="span" aria-live="polite">
                {lastUpdated.toLocaleTimeString()}
              </Text>
            </Row>
            {marketStatus.latest?.status ? (
              <Badge
                variant={marketStatus.latest.status === 'open' ? 'success' : marketStatus.latest.status === 'closed' ? 'error' : 'warning'}
                size="sm"
              >
                {marketStatus.latest.status}
              </Badge>
            ) : null}
          </Stack>

        </Card>

        {isLoading ? (
          <Card padding="var(--ggui-spacing-6)" border>
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Spinner size={24} color="var(--ggui-color-primary-600)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Loading stock data...
              </Text>
            </Stack>
          </Card>
        ) : renderedStocks.length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" border>
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No stock data available.
              </Text>
            </Stack>
          </Card>
        ) : (
          <Stack gap="var(--ggui-spacing-4)">
            {streamError ? (
              <Alert variant="error" title="Live stream issue">
                {streamError}
              </Alert>
            ) : !priceUpdate.latest?.symbol ? (
              <Alert variant="warning" title="Live updates unavailable">
                Waiting for live stream updates.
              </Alert>
            ) : null}
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" aria-live="polite">
              {lastPriceAnnouncement}
            </Text>
            <CardGrid columns={{ sm: 1, md: 1, lg: 3 }} gap="var(--ggui-spacing-4)" role="list">
              {renderedStocks.map((stock, index) => {
                const positive = (stock.change ?? 0) >= 0;
                const accentColor = positive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
                const arrow = positive ? '▲' : '▼';
                const flash = isFlashing(stock.symbol);
                return (
                  <Card
                    key={`${stock.symbol ?? 'stock'}-${index}`}
                    as={Hoverable}
                    padding="var(--ggui-spacing-4)"
                    border
                    shadow="sm"
                    style={{
                      borderColor: accentColor,
                      background: flash ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                    }}
                    role="listitem"
                  >
                    <Stack gap="var(--ggui-spacing-3)">
                      <Heading level={2} color="var(--ggui-color-onSurface)">
                        <Text is="span" size="3xl" weight="bold" color="var(--ggui-color-onSurface">
                          {stock.symbol ?? '—'}
                        </Text>
                      </Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                        {formatPrice(stock.price)}
                      </Text>
                      <Row align="center" gap="var(--ggui-spacing-2)">
                        <Text variant="bodySmall" color={accentColor}>
                          {formatDelta(stock.change)}
                        </Text>
                        <Text variant="label" color={accentColor}>
                          {arrow} {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                );
              })}
            </CardGrid>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const avatarChoices = useMemo(() => {
    if (props.avatarOptions && props.avatarOptions.length > 0) {
      return props.avatarOptions.slice(0, 4);
    }
    return ['😀', '😎', '🧠', '🚀'];
  }, [props.avatarOptions]);
  const roleChoices = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) {
      return props.roleOptions;
    }
    return ['Developer', 'Designer', 'Manager', 'Other'];
  }, [props.roleOptions]);

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar ?? (avatarChoices[0] ?? '😀'));
  const [role, setRole] = useState(props.initialProfile?.role ?? (roleChoices[0] ?? 'Other'));
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);

  useEffect(() => {
    if (!avatar && avatarChoices.length > 0) {
      setAvatar(avatarChoices[0]);
    }
  }, [avatar, avatarChoices]);

  const emailRegex = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/, []);
  const nameError = nameTouched && !name.trim() ? 'Name is required.' : '';
  const emailError = emailTouched
    ? !email.trim()
      ? 'Email is required.'
      : !emailRegex.test(email.trim())
        ? 'Enter a valid email address.'
        : ''
    : '';

  const isStep1Valid = !!name.trim() && !!email.trim() && emailRegex.test(email.trim()) && !!avatar;
  const canProceed = step === 1 ? isStep1Valid : true;

  const progressValue = useMemo(() => {
    if (step === 1) return 33;
    if (step === 2) return 66;
    return 100;
  }, [step]);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!isStep1Valid) return;
    }
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [step, isStep1Valid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');

  const handleComplete = useCallback(async () => {
    if (!isStep1Valid || isSubmitting) return;
    setSubmitError('');
    setIsSubmitting(true);
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar: avatar || avatarChoices[0] || '😀',
      role: role || roleChoices[0] || 'Other',
      emailNotifications,
      theme: theme === 'dark' ? 'dark' : 'light',
    };
    try {
      complete(payload);
    } catch (error) {
      setSubmitError(error instanceof Error ? error.message : 'Failed to complete setup. Please try again.');
    } finally {
      setTimeout(() => {
        setIsSubmitting(false);
      }, 400);
    }
  }, [isStep1Valid, isSubmitting, name, email, avatar, role, emailNotifications, theme, props, complete, avatarChoices, roleChoices]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Row gap="var(--ggui-spacing-2)" wrap aria-label="Onboarding steps">
              <Badge variant={step >= 1 ? 'primary' : 'default'} aria-current={step === 1 ? 'step' : undefined}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'} aria-current={step === 2 ? 'step' : undefined}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'} aria-current={step === 3 ? 'step' : undefined}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          border
        >
          <Box
            key={`step-${step}`}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                {props.avatarOptions.length === 0 ? (
                  <Alert variant="info" title="Avatar options">
                    No avatars provided, showing defaults.
                  </Alert>
                ) : null}
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={nameError}
                  helperText="This will appear on your profile."
                  aria-invalid={!!nameError}
                  aria-describedby={nameError ? 'name-error-text' : undefined}
                />
                {nameError ? <Text id="name-error-text" variant="caption" color="var(--ggui-color-error-500)">{nameError}</Text> : null}
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={emailError}
                  aria-invalid={!!emailError}
                  aria-describedby={emailError ? 'email-error-text' : undefined}
                />
                {emailError ? <Text id="email-error-text" variant="caption" color="var(--ggui-color-error-500)">{emailError}</Text> : null}
                <Stack gap="var(--ggui-spacing-2)">
                  <Text id="avatar-group-label" variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose Avatar</Text>
                  <RadioGroup
                    label="Avatar options"
                    value={avatar}
                    onChange={setAvatar}
                    direction="horizontal"
                    options={avatarChoices.map((emoji) => ({ value: emoji, label: emoji }))}
                  />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                {props.roleOptions.length === 0 ? (
                  <Alert variant="info" title="Role options">
                    No roles provided, showing defaults.
                  </Alert>
                ) : null}
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={roleChoices.map((option) => ({ value: option, label: option }))}

                  helperText="Used to personalize your workspace."
                />
                <Toggle
                  label="Enable email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Stack gap="var(--ggui-spacing-1)"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Stack>
                    <Stack gap="var(--ggui-spacing-1)"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Stack>
                    <Stack gap="var(--ggui-spacing-1)"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Stack>
                    <Stack gap="var(--ggui-spacing-1)"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Stack>
                    <Stack gap="var(--ggui-spacing-1)"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Stack>
                    <Stack gap="var(--ggui-spacing-1)"><Text variant="label">Theme</Text><Text>{theme}</Text></Stack>
                  </Stack>
                </Card>
                {submitError ? (
                  <Alert variant="error" title="Setup failed">
                    {submitError}
                  </Alert>
                ) : null}
                <Alert variant="info" title="Ready to complete?">
                  Confirm your details and click Complete Setup.
                </Alert>
              </Stack>
            )}
          </Box>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Divider margin="0" />
            <Row justify="between" align="center">
              <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
                Back
              </Button>
              <Row gap="var(--ggui-spacing-2)">
                {step < 3 && (
                  <Button
                    variant="primary"
                    onClick={handleNext}
                    disabled={!canProceed}
                  >
                    Next
                  </Button>
                )}
                {step === 3 && (
                  <>
                    <Button variant="outline" onClick={handleBack}>Go Back</Button>
                    <Button variant="primary" onClick={handleComplete} disabled={isSubmitting}>{isSubmitting ? 'Completing...' : 'Complete Setup'}</Button>
                  </>
                )}
              </Row>
            </Row>
            {isSubmitting ? (
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Spinner size={16} />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Finalizing your setup…</Text>
              </Row>
            ) : null}
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}
